function solve(s, order, k) {
    const n = s.length;
    const totalSubstrings = n * (n + 1) / 2;
    let stars = [];
    let totalWithout = totalSubstrings;

    for (let t = 0; t < n; t++) {
        const x = order[t];
        let low = 0, high = stars.length;
        while (low < high) {
            const mid = Math.floor((low + high) / 2);
            if (stars[mid] < x) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        const insertionIndex = low;
        let L = insertionIndex > 0 ? stars[insertionIndex - 1] : -1;
        let R = insertionIndex < stars.length ? stars[insertionIndex] : n;

        const originalLength = R - L - 1;
        const originalContribution = originalLength * (originalLength + 1) / 2;
        totalWithout -= originalContribution;

        const newLeftLength = x - L - 1;
        const newLeftContribution = newLeftLength * (newLeftLength + 1) / 2;
        const newRightLength = R - x - 1;
        const newRightContribution = newRightLength * (newRightLength + 1) / 2;
        totalWithout += newLeftContribution + newRightContribution;

        stars.splice(insertionIndex, 0, x);

        const validCount = totalSubstrings - totalWithout;
        if (validCount >= k) {
            return t;
        }
    }
    return -1;
}
